// ── Naam → email matching ─────────────────────────────────────────
function psp_match_email($naam, $wp_users) {
    $naam_norm = strtolower(trim($naam));
    $best_score = 0; $best_email = null;
    foreach ($wp_users as $u) {
        $dn = strtolower(trim($u->display_name));
        similar_text($naam_norm, $dn, $pct);
        // Bonus voor zelfde voornaam
        $a = explode(' ', $naam_norm); $b = explode(' ', $dn);
        if ($a[0] === $b[0]) $pct = min(100, $pct + 10);
        if ($pct > $best_score) { $best_score = $pct; $best_email = $u->user_email; }
    }
    return ($best_score >= 72) ? $best_email : null;
}

// ── WP gebruikers ophalen ─────────────────────────────────────────
$wp_users = get_users(['fields' => ['ID','display_name','user_email']]);

// Preview of uitvoeren?
$uitvoeren = isset($_GET['run']);
?><!DOCTYPE html><html lang="nl"><head><meta charset="utf-8"><title>PSP Reimport</title>
<style>
body{font-family:-apple-system,sans-serif;max-width:1000px;margin:32px auto;padding:0 20px;font-size:.87rem;color:#333}
h1{color:#d31775} h2{font-size:.95rem;margin:20px 0 6px;color:#555}
table{width:100%;border-collapse:collapse;margin-bottom:16px;font-size:.82rem}
th{background:#f7f7f8;padding:7px 10px;text-align:left;color:#888;border-bottom:2px solid #eee}
td{padding:7px 10px;border-top:1px solid #f0f0f0}
.ok{color:#27ae60;font-weight:700} .skip{color:#e67e22} .err{color:#c0392b;font-weight:700}
a.btn{display:inline-block;background:#d31775;color:#fff;padding:10px 24px;border-radius:8px;text-decoration:none;font-weight:700;margin-top:12px}
</style></head><body>
<h1>PSP — Volledige hernieuwde import</h1>
<?php

// ── Unieke namen → email matchen ──────────────────────────────────
$unieke_namen = [];
foreach ($besch_data as $b) {
    $naam = $b[0];
    if (!isset($unieke_namen[$naam])) {
        $unieke_namen[$naam] = psp_match_email($naam, $wp_users);
    }
}

$n_match  = count(array_filter($unieke_namen));
$n_skip   = count($unieke_namen) - $n_match;

if (!$uitvoeren) {
    // ── Preview ──────────────────────────────────────────────────
    echo "<p>Gevonden: <strong>{$n_match}</strong> matches, <strong>{$n_skip}</strong> zonder WP-account (worden overgeslagen).</p>";
    echo "<p>Klik op <strong>Uitvoeren</strong> om alle tabellen leeg te maken en opnieuw te importeren.</p>";
    echo "<p style='color:#c0392b;font-weight:700'>⚠ Dit wist alle bestaande planningsdata!</p>";
    echo "<a class='btn' href='?sleutel=" . urlencode(PSP_REIMPORT_SLEUTEL) . "&run=1'>▶ Uitvoeren</a>";
    echo "<h2>Naam-matches (eerste 50)</h2><table><thead><tr><th>Naam (Excel)</th><th>WP-account gevonden</th></tr></thead><tbody>";
    $i = 0;
    foreach ($unieke_namen as $naam => $email) {
        if ($i++ >= 50) break;
        echo "<tr><td>" . esc_html($naam) . "</td><td>" . ($email ? "<span class='ok'>✓ " . esc_html($email) . "</span>" : "<span class='skip'>— geen match, overgeslagen —</span>") . "</td></tr>";
    }
    echo "</tbody></table>";

} else {
    // ── Uitvoering ───────────────────────────────────────────────
    echo "<h2>Stap 1: Tabellen leegmaken</h2>";
    $wpdb->query("TRUNCATE TABLE `{$tk}`"); echo "<p class='ok'>✓ Koppelingen leeg</p>";
    $wpdb->query("TRUNCATE TABLE `{$tb}`"); echo "<p class='ok'>✓ Beschikbaarheid leeg</p>";
    $wpdb->query("TRUNCATE TABLE `{$td}`"); echo "<p class='ok'>✓ Diensten leeg</p>";

    echo "<h2>Stap 2: Beschikbaarheid invoegen</h2>";
    $b_ok = 0; $b_skip = 0;
    foreach ($besch_data as $b) {
        [$naam, $week_start, $dagen_json] = $b;
        $email = $unieke_namen[$naam] ?? null;
        if (!$email) { $b_skip++; continue; }
        $wpdb->insert($tb, [
            'naam'       => $naam,
            'email'      => $email,
            'week_start' => $week_start,
            'dagen'      => $dagen_json,
            'voorkeur'   => '',
            'status'     => 'actief',
        ]);
        $b_ok++;
    }
    echo "<p class='ok'>✓ {$b_ok} beschikbaarheid ingevoegd, {$b_skip} overgeslagen (geen WP-account)</p>";

    echo "<h2>Stap 3: Diensten invoegen</h2>";
    $d_ok = 0;
    foreach ($dienst_data as $d) {
        [$og, $datum, $van, $tot, $naam] = $d;
        $wpdb->insert($td, [
            'titel'         => $og,
            'opdrachtgever' => $og,
            'datum'         => $datum,
            'tijdstip_van'  => $van,
            'tijdstip_tot'  => $tot,
            'type_werk'     => $naam,
            'omschrijving'  => '',
            'status'        => 'vervuld',
        ]);
        $d_ok++;
    }
    echo "<p class='ok'>✓ {$d_ok} diensten ingevoegd</p>";

    echo "<h2>Stap 4: Koppelingen invoegen</h2>";
    $k_ok = 0; $k_skip = 0;
    foreach ($kop_data as $k) {
        [$naam, $week_start, $bedrijf, $datum] = $k;
        $email = $unieke_namen[$naam] ?? null;
        if (!$email) { $k_skip++; continue; }

        $bid = $wpdb->get_var($wpdb->prepare(
            "SELECT id FROM `{$tb}` WHERE email=%s AND week_start=%s LIMIT 1",
            $email, $week_start
        ));
        $did = $wpdb->get_var($wpdb->prepare(
            "SELECT id FROM `{$td}` WHERE opdrachtgever=%s AND datum=%s LIMIT 1",
            $bedrijf, $datum
        ));
        if (!$bid || !$did) { $k_skip++; continue; }

        $wpdb->query($wpdb->prepare(
            "INSERT IGNORE INTO `{$tk}` (beschikbaarheid_id, dienst_id) VALUES (%d, %d)",
            $bid, $did
        ));
        $k_ok++;
    }
    echo "<p class='ok'>✓ {$k_ok} koppelingen ingevoegd, {$k_skip} overgeslagen</p>";

    $totaal_b = $wpdb->get_var("SELECT COUNT(*) FROM `{$tb}`");
    $totaal_d = $wpdb->get_var("SELECT COUNT(*) FROM `{$td}`");
    $totaal_k = $wpdb->get_var("SELECT COUNT(*) FROM `{$tk}`");
    echo "<hr><p><strong>Klaar! {$totaal_b} beschikbaarheid · {$totaal_d} diensten · {$totaal_k} koppelingen</strong></p>";
    echo "<p style='color:#888;font-size:.82rem'>Verwijder nu <code>psp-reimport.php</code> uit de repository.</p>";
}
?>
